sp_page.css:
/* !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
Container 3 Row has CSS selector row auto added to our ask of fill-section flex-row
and we have to override the row style else we get a scrollbar at the bottom of the page
see div.sp-row-content.fill-section.flex-row.row below
!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!! */
div.sp-row-content.fill-section.flex-row.row,
div.sp-row-content.fill-section.flexbox.row {
  margin-left: 0;
  margin-right: 0;
}

/* Tasker User Profile */
.v7e13daf81bb94550888aebde6e4bcb47  {
  display: flex;
  flex-grow: 1;
  /* Do not center for OOO Schedule justify-content: center; */
}

/* Scheduled Out of Office */
.v531dae861b43d510e75655f5624bcb60 {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}

/* Out of Office */
.vb15780ab1b8f9910e75655f5624bcb9c {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}

/* 2.8 | 2022-08-13 | mmcc | DFCT0011084 - Page Tree Bi-Fold needs to match the standard layout for flexing header-body-footer start */
/* Tasker Data Table */
.v1fe908a64fc71300d236eb118110c78a {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}


/* Tasker Attachments */
.v5a5d0f5cdb81b300bb8ee536ca96193f {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}

/* 2.8 | 2022-08-13 | mmcc | DFCT0011084 - Page Tree Bi-Fold needs to match the standard layout for flexing header-body-footer end */

/* flex sp-widget for DocInt List */
.v6dedb22adb9fdb0069d100b5ca96195f {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}

/* Below navbar CSS touches the Theme Header
Might be able to move out of Pages and into a Style Sheet on the theme or just delete it, need to POC it
*/
.navbar-nav {     float:none;     margin:0 auto;     display: block;     text-align: center; } .navbar-nav > li {     display: inline-block;     float:none; }

